#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e8+5;
vector<int>prime;
int n,t;
int vis[MAXN];
void zhi(){
	for(int i=2;i<=n;i++){
		if(!vis[i]){
			prime.push_back(i);
		}
		for(int j=0;j<prime.size();j++){
			if(1ll*prime[j]*i>n)break;
			vis[prime[j]*i]=1;			
			if(i%prime[j]==0)break;
		}
	}
}
int main(){
	std::ios::sync_with_stdio(0);
	std::cin>>n>>t;
	zhi();
	while(t--){
		int a;
		std::cin>>a;
		std::cout<<prime[a-1]<<"\n";
	}
}
